answer_code:
import java.util.Scanner;

class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        if (n > 0) {
            System.out.println("正");
        } else if (n < 0) {
            System.out.println("負");
        } else {
            System.out.println("ゼロ");
        }
    }
}
